import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { connectWallet } from '../utils/walletConnector';

// SVG icons for wallets
const TrustWalletIcon = () => (
  <svg width="24" height="24" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path fillRule="evenodd" clipRule="evenodd" d="M16 32C24.8366 32 32 24.8366 32 16C32 7.16344 24.8366 0 16 0C7.16344 0 0 7.16344 0 16C0 24.8366 7.16344 32 16 32Z" fill="#3375BB"/>
    <path fillRule="evenodd" clipRule="evenodd" d="M16.0002 6.92442C19.5533 9.97332 24.1322 10.1695 25.8059 10.1695V15.3023C25.8059 21.6487 20.4261 24.9767 16.0002 26.9996C11.5742 24.9767 6.19434 21.6487 6.19434 15.3023V10.1695C7.87273 10.1695 12.4523 9.97332 16.0002 6.92442Z" fill="white"/>
  </svg>
);

const TonkeeperIcon = () => (
  <svg width="24" height="24" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path fillRule="evenodd" clipRule="evenodd" d="M16 32C24.8366 32 32 24.8366 32 16C32 7.16344 24.8366 0 16 0C7.16344 0 0 7.16344 0 16C0 24.8366 7.16344 32 16 32Z" fill="#0098EA"/>
    <path d="M22.9285 10.7143L15.9999 7.14288L9.07129 10.7143L15.9999 14.2857L22.9285 10.7143ZM9.07129 12.6429L15.9999 16.2143V24.8572L9.07129 21.2858V12.6429ZM22.9285 12.6429L15.9999 16.2143V24.8572L22.9285 21.2858V12.6429Z" fill="white"/>
  </svg>
);

const EthereumIcon = () => (
  <svg width="24" height="24" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path fillRule="evenodd" clipRule="evenodd" d="M16 32C24.8366 32 32 24.8366 32 16C32 7.16344 24.8366 0 16 0C7.16344 0 0 7.16344 0 16C0 24.8366 7.16344 32 16 32Z" fill="#627EEA"/>
    <path d="M16.498 4V12.87L23.995 16.22L16.498 4Z" fill="white" fillOpacity="0.602"/>
    <path d="M16.498 4L9 16.22L16.498 12.87V4Z" fill="white"/>
    <path d="M16.498 21.968V27.995L24 17.616L16.498 21.968Z" fill="white" fillOpacity="0.602"/>
    <path d="M16.498 27.995V21.967L9 17.616L16.498 27.995Z" fill="white"/>
    <path d="M16.498 20.573L23.995 16.22L16.498 12.872V20.573Z" fill="white" fillOpacity="0.2"/>
    <path d="M9 16.22L16.498 20.573V12.872L9 16.22Z" fill="white" fillOpacity="0.602"/>
  </svg>
);

const TonIcon = () => (
  <svg width="24" height="24" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path fillRule="evenodd" clipRule="evenodd" d="M16 32C24.8366 32 32 24.8366 32 16C32 7.16344 24.8366 0 16 0C7.16344 0 0 7.16344 0 16C0 24.8366 7.16344 32 16 32Z" fill="#0088CC"/>
    <path d="M22.9811 9.68421L21.4741 19.5789L18.4604 21.8947H13.5396L10.5259 19.5789L9.01892 9.68421H22.9811Z" fill="white"/>
    <path d="M16 15.7895L18.4604 13.4737L17.7078 18.9474H14.2922L13.5396 13.4737L16 15.7895Z" fill="#0088CC"/>
  </svg>
);

const Login = () => {
  const [address, setAddress] = useState('');
  const [network, setNetwork] = useState('1'); // По умолчанию Ethereum
  const [walletType, setWalletType] = useState('Trust Wallet'); // По умолчанию Trust Wallet
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');
  const [isMobileDevice, setIsMobileDevice] = useState(false);
  const [signedMessage, setSignedMessage] = useState('');

  const { login } = useAuth();
  const navigate = useNavigate();

  // Определяем, является ли устройство мобильным
  useEffect(() => {
    const checkMobile = () => {
      return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
    };
    setIsMobileDevice(checkMobile());
  }, []);

  // Определяем доступные кошельки в зависимости от выбранной сети
  const getAvailableWallets = () => {
    if (network === '1') { // Ethereum
      return ['Trust Wallet'];
    } else if (network === '2') { // TON
      return ['Trust Wallet', 'Tonkeeper'];
    }
    return ['Trust Wallet'];
  };

  // Обработчик изменения сети
  const handleNetworkChange = (e) => {
    const newNetwork = e.target.value;
    setNetwork(newNetwork);

    // Если выбран Ethereum и текущий кошелек - Tonkeeper, меняем на Trust Wallet
    if (newNetwork === '1' && walletType === 'Tonkeeper') {
      setWalletType('Trust Wallet');
    }
  };

  // Обработчик нажатия на кнопку подключения кошелька
  const handleWalletConnect = async (e) => {
    e.preventDefault();

    try {
      setLoading(true);
      setError('');
      setSuccess('');
      setSignedMessage('');

      // Определение сети (ETH или TON)
      const networkType = network === '1' ? 'ETH' : 'TON';

      // Log some debugging information
      console.log('Attempting to connect to wallet:', {
        networkType,
        walletType,
        isMobileDevice,
        userAgent: navigator.userAgent
      });

      try {
        // Подключение к кошельку и получение адреса и подписи
        const { address, signature, message } = await connectWallet(networkType, walletType);

        // Установка адреса в форму и отображение подписанного сообщения
        setAddress(address);
        setSignedMessage(message);

        // Если получен адрес и подпись, выполняем вход
        if (address && signature) {
          try {
            // Обертываем вызов API в try/catch для лучшей обработки ошибок сети
            await login(address, network, signature, walletType);

            setSuccess(`Вход через ${walletType} выполнен успешно!`);

            // Перенаправляем пользователя на страницу профиля
            setTimeout(() => {
              navigate('/profile');
            }, 2000);
          } catch (apiError) {
            console.error('API error during login:', apiError);

            // Обработка ошибок сети при взаимодействии с бэкендом
            if (!apiError.response) {
              setError('Ошибка сети: Не удалось подключиться к серверу. Проверьте ваше соединение с интернетом.');
            } else if (apiError.response.status === 401) {
              setError('Ошибка аутентификации: Сервер отклонил подпись. Попробуйте еще раз.');
            } else if (apiError.response.status === 500) {
              setError('Ошибка сервера: Произошла внутренняя ошибка. Пожалуйста, попробуйте позже.');
            } else {
              setError(apiError.response?.data?.detail || 'Ошибка при подключении к серверу');
            }
          }
        }
      } catch (connectionError) {
        console.error('Connection Error Details:', connectionError);

        // Check for browser extension detection issues
        if (connectionError.message && connectionError.message.includes('extension not detected')) {
          setError(`Расширение ${walletType} не обнаружено. Убедитесь, что оно установлено и активировано.`);
          return;
        }

        // Проверяем, содержит ли ошибка сообщение об открытии приложения
        if (connectionError.message && connectionError.message.includes('Opening')) {
          setSuccess(connectionError.message);
          // На мобильных устройствах сообщение об успешном открытии приложения
          if (isMobileDevice) {
            setSuccess(`Открывается ${walletType}. Пожалуйста, завершите процесс подключения в приложении.`);
          }
        } else {
          throw connectionError;
        }
      }
    } catch (error) {
      console.error('Ошибка при подключении кошелька:', error);

      // More detailed error messages based on common issues
      if (error.code === -32002) {
        setError('Запрос на подключение уже в процессе. Проверьте всплывающие окна вашего кошелька.');
      } else if (error.code === 4001) {
        setError('Запрос на подключение был отклонен пользователем.');
      } else if (error.message && error.message.includes('user rejected')) {
        setError('Вы отклонили запрос на подключение к кошельку.');
      } else if (error.message && error.message.includes('Network Error')) {
        setError('Ошибка сети: Не удалось подключиться к серверу. Проверьте ваше соединение с интернетом и убедитесь, что серверная часть запущена.');
      } else {
        setError(error.message || 'Ошибка при подключении кошелька');
      }
    } finally {
      setLoading(false);
    }
  };

  // Возвращает текст кнопки в зависимости от типа устройства
  const getButtonText = () => {
    if (loading) return 'Подключение...';
    if (isMobileDevice) return `Открыть ${walletType}`;
    return `Подключить ${walletType}`;
  };

  // Получаем иконку сети
  const getNetworkIcon = () => {
    if (network === '1') return <EthereumIcon />;
    if (network === '2') return <TonIcon />;
    return null;
  };

  // Получаем иконку кошелька
  const getWalletIcon = () => {
    if (walletType === 'Trust Wallet') return <TrustWalletIcon />;
    if (walletType === 'Tonkeeper') return <TonkeeperIcon />;
    return null;
  };

  return (
    <div className="container" style={{ maxWidth: '1200px', margin: '0 auto', padding: '20px' }}>
      <div style={{ 
        maxWidth: '500px', 
        margin: '40px auto', 
        boxShadow: '0 4px 20px rgba(0, 0, 0, 0.1)', 
        borderRadius: '12px', 
        overflow: 'hidden' 
      }}>
        {/* Header */}
        <div style={{ 
          background: 'linear-gradient(135deg, #6c63ff, #3b5998)', 
          padding: '30px',
          color: 'white',
          textAlign: 'center'
        }}>
          <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '600' }}>Вход через криптокошелек</h2>
          <p style={{ marginTop: '8px', opacity: 0.8 }}>Безопасная авторизация через {network === '1' ? 'Ethereum' : 'TON'}</p>
        </div>

        {/* Body */}
        <div style={{ padding: '30px' }}>
          {error && (
            <div style={{ 
              padding: '15px', 
              borderRadius: '8px', 
              backgroundColor: '#fff5f5', 
              color: '#e53e3e', 
              marginBottom: '20px',
              border: '1px solid #fed7d7' 
            }}>
              <strong>Ошибка:</strong> {error}
            </div>
          )}

          {success && (
            <div style={{ 
              padding: '15px', 
              borderRadius: '8px', 
              backgroundColor: '#f0fff4', 
              color: '#38a169', 
              marginBottom: '20px',
              border: '1px solid #c6f6d5' 
            }}>
              <strong>Успех:</strong> {success}
            </div>
          )}

          <form onSubmit={handleWalletConnect}>
            {/* Network Selection */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{ 
                display: 'block', 
                marginBottom: '8px', 
                fontWeight: '500',
                color: '#4a5568'
              }}>
                Выберите сеть
              </label>
              <div style={{ position: 'relative' }}>
                <div style={{ 
                  position: 'absolute', 
                  left: '12px', 
                  top: '50%', 
                  transform: 'translateY(-50%)',
                  display: 'flex',
                  alignItems: 'center'
                }}>
                  {getNetworkIcon()}
                </div>
                <select
                  style={{ 
                    width: '100%',
                    padding: '12px 12px 12px 44px', 
                    borderRadius: '8px',
                    border: '1px solid #e2e8f0',
                    appearance: 'none',
                    fontSize: '16px',
                    backgroundColor: '#fff',
                    boxShadow: '0 1px 3px rgba(0, 0, 0, 0.05)',
                    paddingRight: '32px' // Space for the dropdown arrow
                  }}
                  value={network}
                  onChange={handleNetworkChange}
                  disabled={loading}
                >
                  <option value="1">Ethereum</option>
                  <option value="2">TON</option>
                </select>
                <div style={{ 
                  position: 'absolute', 
                  right: '12px', 
                  top: '50%', 
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none'
                }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M6 9L12 15L18 9" stroke="#4a5568" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </div>
              </div>
            </div>

            {/* Wallet Type Selection */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{ 
                display: 'block', 
                marginBottom: '8px', 
                fontWeight: '500',
                color: '#4a5568'
              }}>
                Выберите кошелек
              </label>
              <div style={{ position: 'relative' }}>
                <div style={{ 
                  position: 'absolute', 
                  left: '12px', 
                  top: '50%', 
                  transform: 'translateY(-50%)',
                  display: 'flex',
                  alignItems: 'center'
                }}>
                  {getWalletIcon()}
                </div>
                <select
                  style={{ 
                    width: '100%',
                    padding: '12px 12px 12px 44px', 
                    borderRadius: '8px',
                    border: '1px solid #e2e8f0',
                    appearance: 'none',
                    fontSize: '16px',
                    backgroundColor: '#fff',
                    boxShadow: '0 1px 3px rgba(0, 0, 0, 0.05)',
                    paddingRight: '32px' // Space for the dropdown arrow
                  }}
                  value={walletType}
                  onChange={(e) => setWalletType(e.target.value)}
                  disabled={loading}
                >
                  {getAvailableWallets().map(wallet => (
                    <option key={wallet} value={wallet}>
                      {wallet}
                    </option>
                  ))}
                </select>
                <div style={{ 
                  position: 'absolute', 
                  right: '12px', 
                  top: '50%', 
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none'
                }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M6 9L12 15L18 9" stroke="#4a5568" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </div>
              </div>
            </div>

            {/* Connect Button */}
            <button
              type="submit"
              style={{ 
                width: '100%',
                padding: '14px',
                backgroundColor: '#6c63ff',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                fontSize: '16px',
                fontWeight: '500',
                cursor: loading ? 'not-allowed' : 'pointer',
                opacity: loading ? 0.7 : 1,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'all 0.2s ease',
                boxShadow: '0 4px 6px rgba(108, 99, 255, 0.25)'
              }}
              disabled={loading}
              onMouseOver={(e) => e.currentTarget.style.backgroundColor = '#5a52dd'}
              onMouseOut={(e) => e.currentTarget.style.backgroundColor = '#6c63ff'}
            >
              {loading && (
                <svg style={{ marginRight: '8px', animation: 'spin 1s linear infinite' }} width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22C17.5228 22 22 17.5228 22 12C22 9.27455 20.9097 6.80375 19.1414 5" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              )}
              <span style={{ display: 'flex', alignItems: 'center' }}>
                {!loading && getWalletIcon() && <span style={{ marginRight: '8px' }}>{getWalletIcon()}</span>}
                {getButtonText()}
              </span>
            </button>
          </form>

          {/* Signed message display */}
          {signedMessage && (
            <div style={{ 
              marginTop: '20px', 
              padding: '15px', 
              backgroundColor: '#f8f9fa',
              borderRadius: '8px',
              border: '1px solid #e2e8f0'
            }}>
              <h4 style={{ 
                fontSize: '14px', 
                fontWeight: '600', 
                marginTop: 0, 
                marginBottom: '10px',
                color: '#4a5568'
              }}>
                Подписанное сообщение:
              </h4>
              <pre style={{ 
                fontSize: '12px', 
                whiteSpace: 'pre-wrap', 
                backgroundColor: '#f1f1f1',
                padding: '10px',
                borderRadius: '4px',
                overflowX: 'auto',
                margin: 0
              }}>
                {signedMessage}
              </pre>
            </div>
          )}

          {/* Info section */}
          <div style={{ 
            marginTop: '20px', 
            padding: '15px', 
            backgroundColor: '#ebf8ff',
            borderRadius: '8px',
            fontSize: '14px',
            color: '#2b6cb0',
            border: '1px solid #bee3f8'
          }}>
            <div style={{ display: 'flex', alignItems: 'flex-start' }}>
              <svg style={{ flexShrink: 0, marginRight: '10px', marginTop: '2px' }} width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path fillRule="evenodd" clipRule="evenodd" d="M12 22C17.5228 22 22 17.5228 22 12C22 6.47715 17.5228 2 12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22Z" stroke="#3182ce" strokeWidth="2"/>
                <path d="M12 11V16" stroke="#3182ce" strokeWidth="2" strokeLinecap="round"/>
                <path d="M12 8V8.01" stroke="#3182ce" strokeWidth="2" strokeLinecap="round"/>
              </svg>
              <div>
                {isMobileDevice ? (
                  <p style={{ margin: 0 }}>
                    Нажмите кнопку, чтобы открыть приложение кошелька.
                    <br />
                    {network === '1' ? 'Для Ethereum доступен только Trust Wallet.' : 'Для TON доступны Trust Wallet и Tonkeeper.'}
                  </p>
                ) : (
                  <p style={{ margin: 0 }}>
                    Для входа требуется расширение браузера.
                    <br />
                    {network === '1' ? 'Для Ethereum доступен только Trust Wallet.' : 'Для TON доступны Trust Wallet и Tonkeeper.'}
                  </p>
                )}
              </div>
            </div>
          </div>

          {/* Troubleshooting section */}
          <div style={{ 
            marginTop: '20px', 
            padding: '15px', 
            borderTop: '1px solid #e2e8f0',
            paddingTop: '20px'
          }}>
            <h4 style={{ 
              fontSize: '14px', 
              fontWeight: '600', 
              margin: '0 0 10px 0',
              color: '#4a5568'
            }}>
              Проблемы с подключением?
            </h4>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '10px' }}>
              <button 
                onClick={() => window.location.reload()} 
                style={{
                  backgroundColor: '#f8f9fa',
                  color: '#4a5568',
                  border: '1px solid #e2e8f0',
                  borderRadius: '6px',
                  padding: '8px 16px',
                  fontSize: '14px',
                  fontWeight: '500',
                  cursor: 'pointer',
                  flex: '1',
                  marginRight: '10px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
              >
                <svg style={{ marginRight: '5px' }} width="14" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M20 11C20 6.03 15.97 2 11 2C6.03 2 2 6.03 2 11" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                  <path d="M11 22C15.97 22 20 17.97 20 13V11" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                  <path d="M2 11V13C2 17.97 6.03 22 11 22" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                  <path d="M12 2C13.8565 2 15.637 2.7375 16.9497 4.05025C18.2625 5.36301 19 7.14348 19 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                  <path d="M19 9H13V3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
                Обновить
              </button>
              <a 
                href={walletType === 'Trust Wallet' ? 'https://trustwallet.com/browser-extension' : 'https://tonkeeper.com/extension'}
                target="_blank" 
                rel="noopener noreferrer"
                style={{
                  backgroundColor: '#6c63ff',
                  color: 'white',
                  border: 'none',
                  borderRadius: '6px',
                  padding: '8px 16px',
                  fontSize: '14px',
                  fontWeight: '500',
                  cursor: 'pointer',
                  flex: '1',
                  textDecoration: 'none',
                  textAlign: 'center',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
              >
                <svg style={{ marginRight: '5px' }} width="14" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M21 12L16 7M21 12L16 17M21 12H3" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
                Скачать {walletType}
              </a>
            </div>
          </div>

        </div>
      </div>

      {/* Add animation styles */}
      <style>
        {`
          @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
          }
        `}
      </style>
    </div>
  );
};

export default Login;
